#include<bits/stdc++.h>
using namespace std;
vector<pair<long long,long long>> mp[500050];
vector<pair<long long,long long>> mp1[500050];
long long dis[500050],cnt[500050],x[500050],y[500050];
bool vis[500050];
long long n,m;
bool spfa()
{
    memset(dis,0x3f,sizeof(dis));
    dis[0]=0;
    stack<long long> q;
    q.push(0);
    while(!q.empty())
    {
        long long t=q.top();
        q.pop();
        vis[t]=0;
        for(auto i:mp1[t])
        {
            long long v=i.first,val=i.second;
            if(dis[v]>dis[t]+val)
            {
                cnt[v]=cnt[t]+1;
                if(cnt[v]>n)
                {
                    return false;
                }
                dis[v]=dis[t]+val;
                if(!vis[v])
                {
                    vis[v]=1;
                    q.push(v);
                }
            }
        }
    }
    return true;
}
bool p[500050],vis1[500050];
bool dfs(int x)
{
    if(x==n||p[x])
    {
        return true;
    }
    for(auto i:mp[x])
    {
        int v=i.first,id=i.second;
        if(!vis1[id])
        {
            vis1[id]=true;
            if(dfs(v))
            {
                mp1[x].push_back(make_pair(v,9));
                mp1[v].push_back(make_pair(x,-1));
                p[x]=true;
            }
        }
    }
    return p[x];
}
int main()
{
    scanf("%lld%lld",&n,&m);
    for(long long i=1;i<=m;i++)
    {
        scanf("%lld%lld",&x[i],&y[i]);
        mp[x[i]].push_back(make_pair(y[i],i));
    }
    for(long long i=1;i<=n;i++)
    {
        mp1[0].push_back(make_pair(i,0));
    }
    if(!dfs(1)||!spfa())
    {
        printf("-1");
        return 0;
    }
    printf("%lld %lld\n",n,m);
    for(long long i=1;i<=m;i++)
    {
        printf("%lld %lld ",x[i],y[i]);
        int now=abs(dis[x[i]]-dis[y[i]]);
        if(now>=1&&now<=9)
        {
            printf("%d\n",now);
        }
        else
        {
            printf("1\n");
        }
    }
    return 0;
}
